// GraphQL Type Definitions
const typeDefs = gql`
  enum InvoiceStatus {
    DRAFT
    PENDING
    PAID
    OVERDUE
    CANCELLED
  }

  type Customer {
    id: ID!
    name: String!
    email: String!
    address: String
  }

  type InvoiceItem {
    id: ID!
    description: String!
    quantity: Int!
    unitPrice: Float!
    amount: Float!
  }

  type Invoice {
    id: ID!
    invoiceNumber: String!
    status: InvoiceStatus!
    issueDate: String!
    dueDate: String!
    customer: Customer!
    items: [InvoiceItem!]!
    subtotal: Float!
    taxRate: Float!
    taxAmount: Float!
    totalAmount: Float!
    notes: String
    createdBy: String!
  }

  type Query {
    invoice(id: ID!): Invoice
    invoices(status: InvoiceStatus, limit: Int, offset: Int): InvoiceConnection!
  }

  type InvoiceConnection {
    invoices: [Invoice!]!
    totalCount: Int!
    hasMore: Boolean!
  }

  type Mutation {
    createInvoice(input: CreateInvoiceInput!): Invoice!
    updateInvoiceStatus(id: ID!, status: InvoiceStatus!): Invoice!
    deleteInvoice(id: ID!): DeleteResponse!
  }

  input CreateInvoiceInput {
    invoiceNumber: String!
    dueDate: String!
    customer: CustomerInput!
    items: [InvoiceItemInput!]!
    taxRate: Float!
    notes: String
  }

  input CustomerInput {
    name: String!
    email: String!
    address: String
  }

  input InvoiceItemInput {
    description: String!
    quantity: Int!
    unitPrice: Float!
  }

  type DeleteResponse {
    success: Boolean!
    message: String!
    id: ID!
  }
`;

// Resolvers
const resolvers = {
  Query: {
    invoice: async (parent, { id }, context) => {
      // context.user is available from authentication middleware
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required. Please provide a valid token.');
      }

      const invoice = invoicesDB[id];

      if (!invoice) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      // User has been authenticated by middleware and can query any invoice they have the ID for
      console.log(`User ${user.id} (${user.email}) accessed invoice ${id}`);

      return invoice;
    },

    invoices: async (parent, { status, limit = 10, offset = 0 }, context) => {
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required. Please provide a valid token.');
      }

      let allInvoices = Object.values(invoicesDB);

      // Filter by status if provided
      if (status) {
        allInvoices = allInvoices.filter(inv => inv.status === status);
      }

      const totalCount = allInvoices.length;
      const paginatedInvoices = allInvoices.slice(offset, offset + limit);
      const hasMore = offset + limit < totalCount;

      console.log(`User ${user.id} listed invoices (status: ${status || 'all'}, offset: ${offset}, limit: ${limit})`);

      return {
        invoices: paginatedInvoices,
        totalCount,
        hasMore
      };
    }
  },

  Mutation: {
    createInvoice: async (parent, { input }, context) => {
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required. Please provide a valid token.');
      }

      // Calculate item amounts, subtotal, tax, and total
      const items = input.items.map((item, index) => ({
        id: `ITEM-${Date.now()}-${index}`,
        description: item.description,
        quantity: item.quantity,
        unitPrice: item.unitPrice,
        amount: parseFloat((item.quantity * item.unitPrice).toFixed(2))
      }));

      const subtotal = parseFloat(items.reduce((sum, item) => sum + item.amount, 0).toFixed(2));
      const taxAmount = parseFloat((subtotal * input.taxRate).toFixed(2));
      const totalAmount = parseFloat((subtotal + taxAmount).toFixed(2));

      const newId = `INV-${String(Object.keys(invoicesDB).length + 1).padStart(3, '0')}`;

      const newInvoice = {
        id: newId,
        invoiceNumber: input.invoiceNumber,
        status: 'PENDING',
        issueDate: new Date().toISOString().split('T')[0],
        dueDate: input.dueDate,
        customer: {
          id: `CUST-${Date.now()}`,
          name: input.customer.name,
          email: input.customer.email,
          address: input.customer.address || null
        },
        items,
        subtotal,
        taxRate: input.taxRate,
        taxAmount,
        totalAmount,
        notes: input.notes || null,
        createdBy: user.id
      };

      invoicesDB[newId] = newInvoice;

      console.log(`User ${user.id} created invoice ${newId}`);

      return newInvoice;
    },

    updateInvoiceStatus: async (parent, { id, status }, context) => {
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required. Please provide a valid token.');
      }

      const invoice = invoicesDB[id];

      if (!invoice) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      // Validate status transitions
      const validTransitions = {
        DRAFT: ['PENDING', 'CANCELLED'],
        PENDING: ['PAID', 'OVERDUE', 'CANCELLED'],
        OVERDUE: ['PAID', 'CANCELLED'],
        PAID: [],
        CANCELLED: []
      };

      const allowedStatuses = validTransitions[invoice.status];
      if (!allowedStatuses || !allowedStatuses.includes(status)) {
        throw new Error(
          `Cannot transition invoice from "${invoice.status}" to "${status}". Allowed transitions: ${allowedStatuses.length > 0 ? allowedStatuses.join(', ') : 'none (terminal state)'}.`
        );
      }

      invoice.status = status;

      console.log(`User ${user.id} updated invoice ${id} status to ${status}`);

      return invoice;
    },

    deleteInvoice: async (parent, { id }, context) => {
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required. Please provide a valid token.');
      }

      const invoice = invoicesDB[id];

      if (!invoice) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      // Only allow deletion of DRAFT or CANCELLED invoices
      if (!['DRAFT', 'CANCELLED'].includes(invoice.status)) {
        throw new Error(
          `Cannot delete invoice with status "${invoice.status}". Only DRAFT or CANCELLED invoices can be deleted.`
        );
      }

      delete invoicesDB[id];

      console.log(`User ${user.id} deleted invoice ${id}`);

      return {
        success: true,
        message: `Invoice ${id} has been successfully deleted.`,
        id
      };
    }
  }
};

// Simulated authentication middleware (already verified user)
const authMiddleware = (req, res, next) => {
  // In production, this middleware would have already verified the JWT token
  // Here we simulate an authenticated user being attached to the request
  req.user = {
    id: 'user-123',
    email: 'developer@example.com',
    name: 'John Developer',
    role: 'admin'
  };
  next();
};

// Server setup
async function startServer() {
  const app = express();

  // Apply authentication middleware before Apollo Server
  app.use(authMiddleware);

  const server = new ApolloServer({
    typeDefs,
    resolvers,
    context: ({ req }) => {
      // The user has already been authenticated by middleware
      return {
        user: req.user
      };
    },
    formatError: (error) => {
      console.error('GraphQL Error:', error.message);
      return {
        message: error.message,
        code: error.extensions?.code || 'INTERNAL_SERVER_ERROR',
        path: error.path
      };
    }
  });

  await server.start();
  server.applyMiddleware({ app, path: '/graphql' });

  const PORT = process.env.PORT || 4000;

  app.listen(PORT, () => {
    console.log(`🚀 Invoice Management GraphQL API running at http://localhost:${PORT}${server.graphqlPath}`);
    console.log(`\nSample queries to try:`);
    console.log(`\n1. Get invoice by ID:`);
    console.log(`   query { invoice(id: "INV-001") { id invoiceNumber status totalAmount customer { name email } items { description quantity unitPrice amount } } }`);
    console.log(`\n2. List all invoices:`);
    console.log(`   query { invoices { invoices { id invoiceNumber status totalAmount } totalCount hasMore } }`);
    console.log(`\n3. Filter invoices by status:`);
    console.log(`   query { invoices(status: PENDING) { invoices { id invoiceNumber totalAmount } totalCount } }`);
    console.log(`\n4. Create a new invoice:`);
    console.log(`   mutation { createInvoice(input: { invoiceNumber: "INV-2024-004", dueDate: "2024-06-01", customer: { name: "New Client", email: "client@example.com" }, items: [{ description: "Service", quantity: 1, unitPrice: 500 }], taxRate: 0.08 }) { id totalAmount } }`);
    console.log(`\n5. Update invoice status:`);
    console.log(`   mutation { updateInvoiceStatus(id: "INV-002", status: PAID) { id status } }`);
  });
}

startServer().catch((error) => {
  console.error('Failed to start server:', error);
  process.exit(1);
});

module.exports = { typeDefs, resolvers, invoicesDB };